INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f4906084-3ded-42a0-8f6e-2b9093c961c0',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy Broadcasting — Why Your Loop Is 100x Slower$escape$,
  $escape$Broadcasting lets NumPy apply operations across arrays with different shapes without copying data. When you write `a + b` where `a` is (3,1) and `b` is (1,4), NumPy stretches both to (3,4) virtually — no memory allocation for the expanded arrays.

The rules are simple: dimensions are compared right-to-left, and each pair must either match or one must be 1. Violations raise `ValueError`.

This matters because vectorized broadcasting operates in C-level loops over contiguous memory, while Python `for` loops pay per-element interpreter overhead. A 1000x1000 element-wise multiply is ~200μs vectorized vs ~200ms looped — three orders of magnitude.

Memory layout amplifies this. C-contiguous arrays (row-major, the default) iterate fastest along the last axis. Operating along axis=0 on a C-order array causes cache misses. Use `np.ascontiguousarray()` or reshape your computation to align with storage order. Check with `arr.flags['C_CONTIGUOUS']`.$escape$,
  $escape$import numpy as np

# Vectorized broadcasting vs explicit loop
a = np.random.randn(1000, 1)    # shape (1000, 1)
b = np.random.randn(1, 1000)    # shape (1, 1000)

# Broadcasting: ~0.2ms, produces (1000, 1000)
result = a * b

# Equivalent loop: ~200ms
result_loop = np.empty((1000, 1000))
for i in range(1000):
    for j in range(1000):
        result_loop[i, j] = a[i, 0] * b[0, j]

# Verify memory layout matters
c = np.asfortranarray(result)        # column-major
print(result.flags['C_CONTIGUOUS'])   # True
print(c.flags['F_CONTIGUOUS'])        # True$escape$,
  $escape$python$escape$,
