INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e9f78235-bea8-42a4-91f2-f70999ccb72e',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy Time Series — Rolling Windows and Lag Features Without Pandas$escape$,
  $escape$NumPy's stride tricks and sliding_window_view make time series feature engineering possible without ever touching pandas. np.lib.stride_tricks.sliding_window_view(arr, window_shape) returns a view over rolling windows with zero copy overhead — ideal for computing rolling means, stds, or custom aggregations on raw arrays.

For lag features, simple slicing beats any abstraction: arr[:-k] aligned against arr[k:] gives you lag-k pairs instantly. Stack multiple lags with np.column_stack for regression-ready feature matrices.

Seasonality detection starts with np.fft.rfft. Apply it to your detrended signal and inspect np.abs(freqs) to find dominant periodic components. The index of the peak maps directly to period length via len(signal) / peak_index.

Resampling unevenly spaced data? np.interp handles linear interpolation to a uniform grid, and np.searchsorted bins timestamps into regular intervals for aggregation. These primitives compose cleanly — no DataFrame overhead, no dependency bloat, just arrays and math.$escape$,
  $escape$import numpy as np

# Generate synthetic daily signal with weekly seasonality
t = np.arange(365, dtype=np.float64)
signal = 10 + 2 * np.sin(2 * np.pi * t / 7) + np.random.normal(0, 0.5, 365)

# Rolling mean via sliding_window_view (zero-copy)
from numpy.lib.stride_tricks import sliding_window_view
rolling_mean = sliding_window_view(signal, 7).mean(axis=1)

# Lag features: lag-1 and lag-7
lag1 = signal[:-7]
lag7 = signal[7:] - signal[:-7]  # weekly diff
features = np.column_stack([lag1[:len(lag7)], lag7])

# Detect seasonality via FFT
freqs = np.fft.rfft(signal - signal.mean())
period = len(signal) / np.argmax(np.abs(freqs[1:])) 
print(f"Dominant period: {period:.1f} days")  # ≈ 7.0$escape$,
  $escape$python$escape$,
