INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '428b02c1-461c-40e5-8add-44156f604afc',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy Random Seeds — The Right Way to Lock Down Reproducibility$escape$,
  $escape$NumPy's legacy `np.random.seed()` sets global state, which breaks the moment two libraries touch the same RNG. The modern fix: `np.random.default_rng(seed)` returns an isolated `Generator` instance with no shared state.

Pass the `rng` object explicitly to every function that needs randomness. This makes data pipelines deterministic without side effects. When converting notebooks to scripts, replace scattered `np.random.seed(42)` calls at cell tops with a single `rng = np.random.default_rng(42)` at the entry point.

For full environment reproducibility, pin your NumPy version (`numpy==1.26.4`) — the default BitGenerator changed from `MT19937` to `PCG64` in v1.17, so the same seed produces different sequences across major versions. Use `np.random.PCG64(seed)` explicitly if you need cross-version stability.

Check `rng.bit_generator.state` to snapshot and restore RNG state mid-pipeline. Serialize it with `np.savez` for audit trails. Combine with `np.array_equal()` assertions on outputs to catch silent drift between runs.$escape$,
  $escape$import numpy as np

# Modern approach: isolated Generator, no global state
rng = np.random.default_rng(seed=42)

def sample_batch(data: np.ndarray, n: int, rng: np.random.Generator) -> np.ndarray:
    indices = rng.choice(len(data), size=n, replace=False)
    return data[indices]

data = np.arange(1000)
batch = sample_batch(data, n=50, rng=rng)

# Snapshot RNG state for reproducibility audits
state = rng.bit_generator.state
np.savez('rng_checkpoint.npz', **{k: np.array(v) if not isinstance(v, dict) else k for k, v in state.items()})$escape$,
  $escape$python$escape$,
