INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ad5e5d59-35bc-4ae1-8b29-4b3686785be4',
  '00000000-0000-0000-0000-000000000001',
  $escape$NumPy Data Versioning — Hash Your Arrays to Track Dataset Drift$escape$,
  $escape$Every model version should be pinned to an exact dataset version. NumPy arrays aren't git-friendly — binary blobs diff poorly. Instead, compute a deterministic hash of your array's raw buffer to fingerprint each dataset revision.

Use `array.tobytes()` piped through `hashlib` to generate a content-addressable checksum. Store this hash alongside your model checkpoint metadata. When you reload, recompute and compare — if the hash diverges, your data changed.

For structured datasets, hash individual columns via structured dtypes and store a manifest: shape, dtype, and per-column SHA-256. This catches silent dtype coercions (`float64` → `float32`) that corrupt reproducibility.

Save versioned snapshots with `np.savez_compressed()`, embedding the hash in the filename or as an extra array in the archive. Pair this with `np.array_equal()` for fast equality checks before expensive retraining. The combination of content hashing + compressed archives gives you lightweight, reproducible dataset versioning without heavyweight tools like DVC.$escape$,
  $escape$import numpy as np
import hashlib

def version_dataset(data: np.ndarray, path: str) -> str:
    """Save array with content-based version hash."""
    content_hash = hashlib.sha256(data.tobytes()).hexdigest()[:12]
    meta = np.array([f"sha256:{content_hash}", str(data.dtype), str(data.shape)])
    out_path = f"{path}_v{content_hash}.npz"
    np.savez_compressed(out_path, data=data, meta=meta)
    return content_hash

# Usage
X_train = np.random.randn(10000, 128).astype(np.float32)
version = version_dataset(X_train, "datasets/embeddings")
print(f"Dataset version: {version}")  # e.g. "Dataset version: a3f8b2c1e9d0"$escape$,
  $escape$python$escape$,
